7	export function AppProviders({ children }) {
8	    const [queryClient] = useState(
9	        () =>
10	            new QueryClient({
11	                defaultOptions: {
12	                    queries: {
13	                        retry: false,
14	                    },
15	                    mutations: {
16	                        retry: false,
17	                    },
18	                },
19	            }),
20	    );
21	
22	    return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>;
23	}
