25	/**
26	 * C2 계약: providers.jsx — QueryClientProvider + Toaster 전역 Provider 래핑
27	 * router.jsx의 RouterProvider와 함께 사용.
28	 */
29	export function Providers({ children }) {
30	    const [queryClient] = useState(
31	        () =>
32	            new QueryClient({
33	                defaultOptions: {
34	                    queries: {
35	                        retry: 1,
36	                        staleTime: 1000 * 60 * 5,
37	                    },
38	                },
39	            }),
40	    );
41	
42	    return (
43	        <QueryClientProvider client={queryClient}>
44	            <RouterProvider router={router} />
45	            <Toaster richColors position="top-right" />
46	        </QueryClientProvider>
47	    );
48	}
