1	const TOKEN_KEY = 'trmdict_token';
2	
3	export function getToken() {
4	    return localStorage.getItem(TOKEN_KEY);
5	}
6	
7	export function setToken(token) {
8	    localStorage.setItem(TOKEN_KEY, token);
9	}
10	
11	export function removeToken() {
12	    localStorage.removeItem(TOKEN_KEY);
13	}
14	
15	export function parseToken(token) {
16	    try {
17	        const payload = token.split('.')[1];
18	        return JSON.parse(atob(payload));
19	    } catch {
20	        return null;
21	    }
22	}
