1	import { zodResolver } from '@hookform/resolvers/zod';
2	import { useMutation } from '@tanstack/react-query';
3	import { useForm } from 'react-hook-form';
4	import { useNavigate, useSearchParams } from 'react-router-dom';
5	import { Button } from '@/shared/components/ui/button';
6	import { Input } from '@/shared/components/ui/input';
7	import { setToken } from '@/core/auth/authUtils';
8	import { useAuthStore } from '@/store/useAuthStore';
9	import { login } from './authApi';
10	import { loginSchema } from './login.schema';
11	
12	export function LoginPage() {
13	    const navigate = useNavigate();
14	    const [searchParams] = useSearchParams();
15	    const setUser = useAuthStore((state) => state.setUser);
16	    const returnUrl = searchParams.get('returnUrl') || '/home';
17	    const {
18	        register,
19	        handleSubmit,
20	        formState: { errors },
21	    } = useForm({
22	        resolver: zodResolver(loginSchema),
23	        defaultValues: {
24	            username: '',
25	            password: '',
26	        },
27	    });
28	
29	    const mutation = useMutation({
30	        mutationFn: login,
31	        onSuccess: (data) => {
32	            setToken(data.accessToken);
33	            setUser(data.user);
34	            navigate(returnUrl, { replace: true });
35	        },
36	    });
37	
38	    return (
39	        <section className='w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-xl shadow-slate-200/60'>
40	            <header className='mb-6 space-y-2'>
41	                <h1 className='text-2xl font-semibold text-slate-900'>TrmWordDict</h1>
42	                <p className='text-sm text-slate-500'>행정 용어 사전 시스템</p>
43	            </header>
44	            <form className='space-y-4' onSubmit={handleSubmit((values) => mutation.mutate(values))}>
45	                <div className='space-y-2'>
46	                    <label className='text-sm font-medium text-slate-700' htmlFor='username'>
47	                        아이디
48	                    </label>
49	                    <Input id='username' autoComplete='username' {...register('username')} />
50	                    {errors.username ? <p className='text-sm text-rose-600'>{errors.username.message}</p> : null}
51	                </div>
52	                <div className='space-y-2'>
53	                    <label className='text-sm font-medium text-slate-700' htmlFor='password'>
54	                        비밀번호
55	                    </label>
56	                    <Input id='password' type='password' autoComplete='current-password' {...register('password')} />
57	                    {errors.password ? <p className='text-sm text-rose-600'>{errors.password.message}</p> : null}
58	                </div>
59	                {mutation.isError ? <p className='text-sm text-rose-600'>로그인에 실패했습니다.</p> : null}
60	                <Button className='w-full' type='submit' disabled={mutation.isPending}>
61	                    로그인
62	                </Button>
63	            </form>
64	        </section>
65	    );
66	}
