13	export function FileUpload({
14	    accept = '.csv',
15	    maxSizeMB = 50,
16	    label = '파일 선택',
17	    onFileSelected,
18	    onFileRejected,
19	}) {
20	    const handleFile = (file) => {
21	        if (!matchesAccept(accept, file.name)) {
22	            onFileRejected?.({
23	                reason: 'TYPE',
24	                message: `허용되지 않는 파일 형식입니다. (${accept}만 허용)`,
25	            });
26	            return;
27	        }
28	
29	        if (file.size > maxSizeMB * 1024 * 1024) {
30	            onFileRejected?.({
31	                reason: 'SIZE',
32	                message: `파일 크기가 ${maxSizeMB}MB를 초과했습니다.`,
33	            });
34	            return;
35	        }
36	
37	        onFileSelected?.(file);
