14	export function DataGrid({
15	    columns = [],
16	    pageData = null,
17	    pageSizeOptions = [10, 20, 50, 100],
18	    selectable = false,
19	    onPageChange,
20	    onSortChange,
21	    onSelectionChange,
22	    onRowClick,
23	}) {
24	    const rows = pageData?.items ?? [];
25	    const [sorting, setSorting] = useState([]);
26	    const [selectedKeys, setSelectedKeys] = useState([]);
27	    const { widths, getResizeProps } = useColumnResize(columns);
28	
29	    const tableColumns = useMemo(
30	        () =>
31	            columns.map((column) => ({
32	                accessorKey: column.key,
33	                header: column.header,
34	                cell: ({ row }) =>
35	                    column.cell
36	                        ? column.cell({ value: row.original[column.key], row: row.original })
37	                        : row.original[column.key],
38	                meta: column,
39	            })),
40	        [columns],
41	    );
42	
43	    const table = useReactTable({
44	        data: rows,
45	        columns: tableColumns,
46	        getCoreRowModel: getCoreRowModel(),
47	    });
48	
49	    const toggleSort = (column) => {
50	        if (!column.sortable) {
51	            return;
52	        }
53	
54	        const currentDirection = sorting[0]?.id === column.key ? sorting[0].desc : undefined;
55	        const nextDirection = currentDirection === undefined ? 'asc' : currentDirection === false ? 'desc' : '';
56	
57	        setSorting(nextDirection ? [{ id: column.key, desc: nextDirection === 'desc' }] : []);
58	        onSortChange?.({ active: column.key, direction: nextDirection });
59	    };
60	
61	    const isAllSelected = rows.length > 0 && selectedKeys.length === rows.length;
62	
63	    const updateSelection = (nextRows) => {
64	        setSelectedKeys(nextRows.map((row) => row.id ?? JSON.stringify(row)));
65	        onSelectionChange?.(nextRows);
66	    };
67	
68	    const toggleAll = () => {
69	        if (isAllSelected) {
70	            updateSelection([]);
71	            return;
72	        }
73	
74	        updateSelection(rows);
75	    };
76	
77	    const toggleRow = (row) => {
78	        const rowKey = row.id ?? JSON.stringify(row);
79	        const exists = selectedKeys.includes(rowKey);
80	        const nextRows = exists
81	            ? rows.filter((item) => (item.id ?? JSON.stringify(item)) !== rowKey)
82	            : rows.filter((item) => selectedKeys.includes(item.id ?? JSON.stringify(item))).concat(row);
83	
84	        updateSelection(nextRows);
85	    };
86	
87	    return (
88	        <section className='overflow-hidden rounded-lg border border-slate-200 bg-white shadow-sm'>
89	            <Table>
90	                <TableHeader>
91	                    <TableRow>
92	                        {selectable ? (
93	                            <TableHead className='w-14'>
94	                                <input
95	                                    type='checkbox'
96	                                    aria-label='Select all rows'
97	                                    checked={isAllSelected}
98	                                    onChange={toggleAll}
99	                                />
100	                            </TableHead>
101	                        ) : null}
102	                        {table.getHeaderGroups().map((headerGroup) =>
103	                            headerGroup.headers.map((header) => {
104	                                const meta = header.column.columnDef.meta;
105	                                const width = widths[meta.key] ?? meta.width;
106	
107	                                return (
108	                                    <TableHead
109	                                        key={header.id}
110	                                        className={getTextAlignClassName(meta.align)}
111	                                        style={width ? { width: `${width}px` } : undefined}
112	                                        {...getResizeProps(meta)}
113	                                    >
114	                                        {meta.sortable ? (
115	                                            <button
116	                                                type='button'
117	                                                aria-label={`Sort by ${meta.header}`}
118	                                                className='inline-flex items-center gap-1 text-inherit'
119	                                                onClick={() => toggleSort(meta)}
120	                                            >
121	                                                <span>{flexRender(header.column.columnDef.header, header.getContext())}</span>
122	                                                <span className='text-xs text-slate-400'>
123	                                                    {sorting[0]?.id === meta.key
124	                                                        ? sorting[0].desc
125	                                                            ? '▼'
126	                                                            : '▲'
127	                                                        : '–'}
128	                                                </span>
129	                                            </button>
130	                                        ) : (
131	                                            flexRender(header.column.columnDef.header, header.getContext())
132	                                        )}
133	                                    </TableHead>
134	                                );
135	                            }),
136	                        )}
137	                    </TableRow>
138	                </TableHeader>
139	                <TableBody>
140	                    {table.getRowModel().rows.map((row) => {
141	                        const rowKey = row.original.id ?? JSON.stringify(row.original);
142	                        const checked = selectedKeys.includes(rowKey);
143	
144	                        return (
145	                            <TableRow
146	                                key={row.id}
147	                                data-state={checked ? 'selected' : undefined}
148	                                className='cursor-pointer'
149	                                onClick={() => onRowClick?.(row.original)}
150	                            >
151	                                {selectable ? (
152	                                    <TableCell className='w-14' onClick={(event) => event.stopPropagation()}>
153	                                        <input
154	                                            type='checkbox'
155	                                            aria-label={`Select row ${row.index + 1}`}
156	                                            checked={checked}
157	                                            onChange={() => toggleRow(row.original)}
158	                                        />
159	                                    </TableCell>
160	                                ) : null}
161	                                {row.getVisibleCells().map((cell) => {
162	                                    const meta = cell.column.columnDef.meta;
163	
164	                                    return (
165	                                        <TableCell
166	                                            key={cell.id}
167	                                            className={cn(getTextAlignClassName(meta.align))}
168	                                        >
169	                                            {flexRender(cell.column.columnDef.cell, cell.getContext())}
170	                                        </TableCell>
171	                                    );
172	                                })}
173	                            </TableRow>
174	                        );
175	                    })}
176	                </TableBody>
177	            </Table>
178	
179	            {pageData ? (
180	                <footer className='flex flex-wrap items-center justify-between gap-3 border-t border-slate-200 px-4 py-3'>
181	                    <div className='text-sm text-slate-500'>
182	                        Page {pageData.page} of {pageData.totalPages} 쨌 {pageData.totalElements} items
183	                    </div>
184	                    <div className='flex items-center gap-2'>
185	                        <select
186	                            aria-label='Page size'
187	                            className='h-9 rounded-md border border-slate-300 bg-white px-3 text-sm'
188	                            value={pageData.size}
189	                            onChange={(event) =>
190	                                onPageChange?.({
191	                                    page: 1,
192	                                    size: Number(event.target.value),
193	                                })
194	                            }
195	                        >
196	                            {pageSizeOptions.map((option) => (
197	                                <option key={option} value={option}>
198	                                    {option} / page
199	                                </option>
200	                            ))}
201	                        </select>
202	                        <Button
203	                            variant='outline'
204	                            disabled={pageData.page <= 1}
205	                            onClick={() => onPageChange?.({ page: pageData.page - 1, size: pageData.size })}
206	                        >
207	                            Previous page
208	                        </Button>
209	                        <Button
210	                            variant='outline'
211	                            disabled={pageData.page >= pageData.totalPages}
212	                            onClick={() => onPageChange?.({ page: pageData.page + 1, size: pageData.size })}
213	                        >
214	                            Next page
215	                        </Button>
216	                    </div>
217	                </footer>
218	            ) : null}
219	        </section>
220	    );
221	}
