1	import { useMemo, useState } from 'react';
2	
3	export function useColumnResize(columns) {
4	    const initialWidths = useMemo(
5	        () =>
6	            columns.reduce((acc, column) => {
7	                if (column.width) {
8	                    acc[column.key] = column.width;
9	                }
10	                return acc;
11	            }, {}),
12	        [columns],
13	    );
14	
15	    const [widths, setWidths] = useState(initialWidths);
16	
17	    const getResizeProps = (column) => ({
18	        onMouseDown: (event) => {
19	            const startX = event.clientX;
20	            const startWidth = widths[column.key] ?? column.width ?? event.currentTarget.getBoundingClientRect().width;
21	            const minWidth = column.minWidth ?? 60;
22	
23	            const handleMove = (moveEvent) => {
24	                const nextWidth = Math.max(minWidth, startWidth + moveEvent.clientX - startX);
25	                setWidths((current) => ({
26	                    ...current,
27	                    [column.key]: nextWidth,
28	                }));
29	            };
30	
31	            const handleUp = () => {
32	                window.removeEventListener('mousemove', handleMove);
33	                window.removeEventListener('mouseup', handleUp);
34	            };
35	
36	            window.addEventListener('mousemove', handleMove);
37	            window.addEventListener('mouseup', handleUp);
38	        },
39	    });
40	
41	    return {
42	        widths,
43	        getResizeProps,
44	    };
45	}
